package com.cardiofit.flink.models;

import com.fasterxml.jackson.annotation.JsonProperty;
import java.io.Serializable;
import java.time.Instant;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * Enriched event model representing events with additional context and derived data
 * Generated by Module 2: Context Assembly & Enrichment
 *
 * Data Flow:
 * - Module 1: Ingests raw events
 * - Module 2: Adds patient context, generates immediateAlerts, riskIndicators, clinicalScores
 * - Module 3: Adds semantic enrichment (potentialInteractions, applicableProtocols)
 * - Module 4: Consumes for CEP pattern matching using riskIndicators
 */
public class EnrichedEvent implements Serializable {
    private static final long serialVersionUID = 2L;  // Updated for new fields

    @JsonProperty("id")
    private String id;

    @JsonProperty("patient_id")
    private String patientId;

    @JsonProperty("encounter_id")
    private String encounterId;

    @JsonProperty("event_type")
    private EventType eventType;

    @JsonProperty("event_time")
    private long eventTime;

    @JsonProperty("processing_time")
    private long processingTime;

    @JsonProperty("source_system")
    private String sourceSystem;

    @JsonProperty("payload")
    private Map<String, Object> payload;

    @JsonProperty("patient_context")
    private PatientContext patientContext;

    @JsonProperty("enrichment_data")
    private Map<String, Object> enrichmentData;

    @JsonProperty("enrichment_version")
    private String enrichmentVersion;

    @JsonProperty("correlation_id")
    private String correlationId;

    // ========== NEW FIELDS - Module 2 Enrichment ==========

    /**
     * Immediate alerts generated by Module 2 threshold checks
     * Simple threshold-based alerts that don't require pattern matching
     * Examples: HR > 140, SBP < 90, Temp > 38.3°C
     * Populated by: Module 2 (Context Assembly & Enrichment)
     */
    @JsonProperty("immediate_alerts")
    private List<SimpleAlert> immediateAlerts;

    /**
     * Primary clinical finding - headline alert for dashboard display
     * Single most critical clinical issue requiring immediate attention
     * Examples: "HYPERTENSIVE CRISIS", "SEVERE SEPSIS RISK", "ACUTE HYPOXIA"
     * Populated by: Module 2 based on highest severity alert or risk assessment
     */
    @JsonProperty("primary_clinical_finding")
    private String primaryClinicalFinding;

    /**
     * Risk indicators for CEP pattern matching
     * Structured boolean flags replacing manual vital extraction in CEP patterns
     * Enables patterns like: event.riskIndicators.tachycardia && event.riskIndicators.hypotension
     * Populated by: Module 2 buildRiskIndicators() method
     */
    @JsonProperty("risk_indicators")
    private RiskIndicators riskIndicators;

    /**
     * Clinical scoring systems calculated by Module 2
     * Key examples: "mews_score" -> 5.0, "qsofa_score" -> 2.0, "news2_score" -> 7.0, "sofa_score" -> 3.0
     * Populated by: Module 2 calculateClinicalScores() method
     */
    @JsonProperty("clinical_scores")
    private Map<String, Double> clinicalScores;

    // ========== NEW FIELDS - Module 3 Semantic Enrichment ==========

    /**
     * Potential drug interactions detected by semantic enrichment
     * Added by Module 3 after knowledge base consultation
     * Empty list if no interactions detected
     * Populated by: Module 3 (Semantic Enrichment)
     */
    @JsonProperty("potential_interactions")
    private List<DrugInteraction> potentialInteractions;

    /**
     * Clinical protocols relevant to current patient state
     * Examples: "sepsis_bundle", "aki_prevention", "vte_prophylaxis", "glycemic_control"
     * Populated by: Module 3 (Semantic Enrichment)
     */
    @JsonProperty("applicable_protocols")
    private List<String> applicableProtocols;

    // Default constructor
    public EnrichedEvent() {
        this.processingTime = System.currentTimeMillis();
        this.enrichmentVersion = "2.0";
        this.immediateAlerts = new ArrayList<>();
        this.clinicalScores = new HashMap<>();
        this.potentialInteractions = new ArrayList<>();
        this.applicableProtocols = new ArrayList<>();
    }

    // Builder pattern
    public static Builder builder() {
        return new Builder();
    }

    public static class Builder {
        private EnrichedEvent event = new EnrichedEvent();

        public Builder id(String id) {
            event.id = id;
            return this;
        }

        public Builder patientId(String patientId) {
            event.patientId = patientId;
            return this;
        }

        public Builder encounterId(String encounterId) {
            event.encounterId = encounterId;
            return this;
        }

        public Builder eventType(EventType eventType) {
            event.eventType = eventType;
            return this;
        }

        public Builder eventTime(long eventTime) {
            event.eventTime = eventTime;
            return this;
        }

        public Builder processingTime(long processingTime) {
            event.processingTime = processingTime;
            return this;
        }

        public Builder sourceSystem(String sourceSystem) {
            event.sourceSystem = sourceSystem;
            return this;
        }

        public Builder payload(Map<String, Object> payload) {
            event.payload = payload;
            return this;
        }

        public Builder patientContext(PatientContext patientContext) {
            event.patientContext = patientContext;
            return this;
        }

        public Builder enrichmentData(Map<String, Object> enrichmentData) {
            event.enrichmentData = enrichmentData;
            return this;
        }

        public Builder correlationId(String correlationId) {
            event.correlationId = correlationId;
            return this;
        }

        // New field builders
        public Builder immediateAlerts(List<SimpleAlert> immediateAlerts) {
            event.immediateAlerts = immediateAlerts;
            return this;
        }

        public Builder addImmediateAlert(SimpleAlert alert) {
            if (event.immediateAlerts == null) {
                event.immediateAlerts = new ArrayList<>();
            }
            event.immediateAlerts.add(alert);
            return this;
        }

        public Builder riskIndicators(RiskIndicators riskIndicators) {
            event.riskIndicators = riskIndicators;
            return this;
        }

        public Builder clinicalScores(Map<String, Double> clinicalScores) {
            event.clinicalScores = clinicalScores;
            return this;
        }

        public Builder addClinicalScore(String scoreName, Double score) {
            if (event.clinicalScores == null) {
                event.clinicalScores = new HashMap<>();
            }
            event.clinicalScores.put(scoreName, score);
            return this;
        }

        public Builder potentialInteractions(List<DrugInteraction> potentialInteractions) {
            event.potentialInteractions = potentialInteractions;
            return this;
        }

        public Builder addPotentialInteraction(DrugInteraction interaction) {
            if (event.potentialInteractions == null) {
                event.potentialInteractions = new ArrayList<>();
            }
            event.potentialInteractions.add(interaction);
            return this;
        }

        public Builder applicableProtocols(List<String> applicableProtocols) {
            event.applicableProtocols = applicableProtocols;
            return this;
        }

        public Builder addApplicableProtocol(String protocol) {
            if (event.applicableProtocols == null) {
                event.applicableProtocols = new ArrayList<>();
            }
            event.applicableProtocols.add(protocol);
            return this;
        }

        public EnrichedEvent build() {
            return event;
        }
    }

    // Getters and Setters
    public String getId() { return id; }
    public void setId(String id) { this.id = id; }

    public String getPatientId() { return patientId; }
    public void setPatientId(String patientId) { this.patientId = patientId; }

    public String getEncounterId() { return encounterId; }
    public void setEncounterId(String encounterId) { this.encounterId = encounterId; }

    public EventType getEventType() { return eventType; }
    public void setEventType(EventType eventType) { this.eventType = eventType; }

    public long getEventTime() { return eventTime; }
    public void setEventTime(long eventTime) { this.eventTime = eventTime; }

    public long getProcessingTime() { return processingTime; }
    public void setProcessingTime(long processingTime) { this.processingTime = processingTime; }

    public String getSourceSystem() { return sourceSystem; }
    public void setSourceSystem(String sourceSystem) { this.sourceSystem = sourceSystem; }

    public Map<String, Object> getPayload() { return payload; }
    public void setPayload(Map<String, Object> payload) { this.payload = payload; }

    public PatientContext getPatientContext() { return patientContext; }
    public void setPatientContext(PatientContext patientContext) { this.patientContext = patientContext; }

    public Map<String, Object> getEnrichmentData() { return enrichmentData; }
    public void setEnrichmentData(Map<String, Object> enrichmentData) { this.enrichmentData = enrichmentData; }

    public String getEnrichmentVersion() { return enrichmentVersion; }
    public void setEnrichmentVersion(String enrichmentVersion) { this.enrichmentVersion = enrichmentVersion; }

    public String getCorrelationId() { return correlationId; }
    public void setCorrelationId(String correlationId) { this.correlationId = correlationId; }

    // Getters and Setters for new fields
    public List<SimpleAlert> getImmediateAlerts() { return immediateAlerts; }
    public void setImmediateAlerts(List<SimpleAlert> immediateAlerts) { this.immediateAlerts = immediateAlerts; }

    public String getPrimaryClinicalFinding() { return primaryClinicalFinding; }
    public void setPrimaryClinicalFinding(String primaryClinicalFinding) { this.primaryClinicalFinding = primaryClinicalFinding; }

    public RiskIndicators getRiskIndicators() { return riskIndicators; }
    public void setRiskIndicators(RiskIndicators riskIndicators) { this.riskIndicators = riskIndicators; }

    public Map<String, Double> getClinicalScores() { return clinicalScores; }
    public void setClinicalScores(Map<String, Double> clinicalScores) { this.clinicalScores = clinicalScores; }

    public List<DrugInteraction> getPotentialInteractions() { return potentialInteractions; }
    public void setPotentialInteractions(List<DrugInteraction> potentialInteractions) { this.potentialInteractions = potentialInteractions; }

    public List<String> getApplicableProtocols() { return applicableProtocols; }
    public void setApplicableProtocols(List<String> applicableProtocols) { this.applicableProtocols = applicableProtocols; }

    /**
     * Get the acuity score from enrichment data
     */
    public double getAcuityScore() {
        if (enrichmentData != null && enrichmentData.containsKey("acuity_score")) {
            Object score = enrichmentData.get("acuity_score");
            if (score instanceof Number) {
                return ((Number) score).doubleValue();
            }
        }
        return 0.0;
    }

    /**
     * Check if this event indicates a critical condition
     */
    public boolean isCritical() {
        return getAcuityScore() > 75.0 || eventType.isCritical();
    }

    /**
     * Get the context age in hours
     */
    public double getContextAgeHours() {
        if (enrichmentData != null && enrichmentData.containsKey("context_age_hours")) {
            Object age = enrichmentData.get("context_age_hours");
            if (age instanceof Number) {
                return ((Number) age).doubleValue();
            }
        }
        return 0.0;
    }

    /**
     * Check if this event has any immediate alerts
     */
    public boolean hasImmediateAlerts() {
        return immediateAlerts != null && !immediateAlerts.isEmpty();
    }

    /**
     * Check if this event has critical immediate alerts
     */
    public boolean hasCriticalAlerts() {
        if (immediateAlerts == null) return false;
        return immediateAlerts.stream()
            .anyMatch(alert -> alert.getSeverity() == AlertSeverity.CRITICAL);
    }

    /**
     * Get a specific clinical score by name
     */
    public Double getClinicalScore(String scoreName) {
        if (clinicalScores == null) return null;
        return clinicalScores.get(scoreName);
    }

    /**
     * Check if this event has any drug interactions
     */
    public boolean hasDrugInteractions() {
        return potentialInteractions != null && !potentialInteractions.isEmpty();
    }

    /**
     * Check if this event has high severity drug interactions
     */
    public boolean hasHighSeverityInteractions() {
        if (potentialInteractions == null) return false;
        return potentialInteractions.stream()
            .anyMatch(interaction -> "HIGH".equals(interaction.getSeverity()) ||
                                    "CRITICAL".equals(interaction.getSeverity()));
    }

    /**
     * Check if a specific protocol is applicable
     */
    public boolean hasProtocol(String protocol) {
        return applicableProtocols != null && applicableProtocols.contains(protocol);
    }

    @Override
    public String toString() {
        return "EnrichedEvent{" +
            "id='" + id + '\'' +
            ", patientId='" + patientId + '\'' +
            ", eventType=" + eventType +
            ", eventTime=" + Instant.ofEpochMilli(eventTime) +
            ", acuityScore=" + getAcuityScore() +
            ", immediateAlerts=" + (immediateAlerts != null ? immediateAlerts.size() : 0) +
            ", hasCriticalAlerts=" + hasCriticalAlerts() +
            ", riskIndicators=" + (riskIndicators != null ? "present" : "null") +
            ", clinicalScores=" + (clinicalScores != null ? clinicalScores.keySet() : "[]") +
            ", drugInteractions=" + (potentialInteractions != null ? potentialInteractions.size() : 0) +
            ", applicableProtocols=" + (applicableProtocols != null ? applicableProtocols.size() : 0) +
            '}';
    }
}